p.BIZ_NO = #{bizNo}

    AND UPPER(p.PRODUCT_NAME) LIKE '%' || UPPER(#{keyword}) || '%'


    AND p.CATEGORY_ID = #{categoryId}


    AND p.STATUS_CD = #{statusCd}

mapper.update:
UPDATE TB_PRODUCT
SET PRODUCT_NAME = #{productName}, CATEGORY_ID = #{categoryId}, PRICE = #{price},
    SALE_PRICE = #{salePrice}, STOCK_QTY = #{stockQty}, DESCRIPTION = #{description},
    BRAND_NAME = #{brandName}, STATUS_CD = #{statusCd}
WHERE PRODUCT_ID = #{productId} AND BIZ_NO = #{bizNo}
